export const cwActivities: Activity[] = [
  {"id":"cw-paper-plate-circle-weave","title":"Paper Plate Circle Weaving","altNames":["Round Loom Plate Weave","Spoke-Weave Sun Disc","Paper Plate Mandala Weave"],"type":"Craft","place":"Both","ageMin":7,"ageMax":12,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Notch the rim of a paper plate into spokes, then spiral yarn over and under to weave a bright round mandala you can hang in a window.","materials":["Sturdy paper plates, one per child","Yarn, assorted colors","Scissors, child-safe","Masking tape, one roll"],"materialTags":["Paper plates","Yarn","Scissors","Masking tape"],"steps":["Cut an odd number of small notches (9 or 11) evenly around the plate rim so the warp will lock without slipping.","Tape one yarn end to the back, then stretch yarn across the plate from notch to notch to form straight warp spokes meeting near the center.","Tie a new color to a center spoke and weave it over one spoke and under the next, spiraling outward round by round.","To change colors, tie the new yarn to the old with a small knot tucked behind the work and keep spiraling.","Push each round snug toward the center so there are no gaps, and stop a finger-width from the rim.","Tuck and tape the final tail on the back, then add a yarn loop through one rim notch for hanging."],"notes":"An odd spoke count is what makes the over-under alternate cleanly each lap; with an even count the pattern stacks and looks messy. Pre-notch plates for the youngest groups so they jump straight to weaving.","safety":"Remind kids to cut the rim notches pointing the scissors away from their holding hand, since the plate edge sits close to their fingers.","ages":["g13","g46"],"rating":0,"media":[{"title":"Paper plate weaving for kids","url":"https://www.youtube.com/watch?v=caRdgCNCPEA"}],"links":[{"label":"How-to & more ideas","url":"https://www.redtedart.com/category/paper-crafts/"}],"variations":["Leave the center spokes bare and only weave the outer third for a quick dream-catcher look.","Weave with two strands of contrasting yarn held together for a marbled effect."],"subsets":[["Mark notch spots with a marker first so spacing stays even","Younger kids can use 9 notches for a faster finish"],[],["Hold the working yarn taut but not tight or the plate will buckle"],[],[],[]]},
  {"id":"cw-stick-twig-weave","title":"Twig Stick Weaving","altNames":["Branch Loom Weaving","Found-Stick Wall Hanging","Y-Stick Yarn Weave"],"type":"Craft","place":"Both","ageMin":8,"ageMax":14,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Wrap warp threads across a forked or straight twig and weave colorful yarn into a rustic little wall hanging that swings from its own branch.","materials":["Straight or Y-shaped twigs, one per child","Yarn, assorted colors","Scissors, child-safe"],"materialTags":["Yarn","Scissors","No materials"],"steps":["Gather sturdy twigs about a hand-and-a-half long; a Y-fork or a single straight stick both work as the top bar.","Tie yarn to one end of the stick, then loop it back and forth down to make several parallel warp threads hanging below.","Knot the bottom of all warp threads to a second small twig so the warp stays evenly spaced and taut.","Weave a new color over and under the warp threads, row by row, pushing each row up snug against the last.","Switch colors whenever you like, leaving short tails at the back that you can trim later.","Tie a yarn hanger across the top twig and snip the bottom warp loose into a little fringe."],"notes":"Forks and slightly bent twigs give the most charm, so let kids hunt for character sticks first. If warp threads slip, a dab of tape or a wrap-around knot at each end locks them.","safety":"Have kids inspect twigs and snap off any sharp broken points before weaving so nobody gets jabbed.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Weaving on a Y-stick loom","url":"https://www.youtube.com/watch?v=3FHofUl6edQ"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/summer-crafts-for-kids/"}],"variations":["Add a few beads onto the fringe ends for weight and sparkle.","Weave a small pocket by wrapping around just two warp threads for several rows."],"subsets":[["Collect twigs on a short nature walk if time allows"],[],["A bottom twig is optional but keeps the weave from curling"],[],[],[]]},
  {"id":"cw-cardboard-coaster-weave","title":"Woven Yarn Coasters","altNames":["Mini Loom Coasters","Square Weave Coasters","Cardboard Mug Mats"],"type":"Craft","place":"Both","ageMin":7,"ageMax":13,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Notch a small cardboard square into a tiny loom and weave a tight, sturdy yarn coaster that actually holds a cup at home.","materials":["Cardboard squares, about palm-sized, one per child","Yarn, assorted colors","Scissors, child-safe","Masking tape, one roll"],"materialTags":["Cardboard","Yarn","Scissors","Masking tape"],"steps":["Cut an odd number of small slits along the top and bottom edges of the cardboard square, lining them up across from each other.","Run yarn straight down through each top slit to the matching bottom slit to lay your warp, taping the start and end on the back.","Thread a long yarn 'needle' length and weave over-under across the warp, turning at each edge to come back the other way.","Each return row should go opposite to the row before, and packed tight so the coaster ends up dense.","Change colors in stripes by tying on new yarn at the edge and tucking the tail behind.","Flip the loom over, snip the warp loops, and knot pairs of warp ends together to free the coaster and finish the edge."],"notes":"Tight packing is the whole game here; a loose weave makes a floppy coaster, so coach kids to push rows down hard with their fingers. A second matching one makes a gift pair.","safety":"When freeing the coaster, make small careful snips of the warp loops one at a time rather than one big cut across fingers.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"DIY coasters on a cardboard loom","url":"https://www.youtube.com/watch?v=RH5aq89vZVM"}],"links":[{"label":"How-to & more ideas","url":"https://www.redtedart.com/category/paper-crafts/"}],"variations":["Make a set of four in camp colors for a themed gift.","Weave the warp in one color and the weft in another for a clean two-tone look."],"subsets":[["Keep slits shallow, about a fingernail deep, so the cardboard stays strong"],[],["Wrap a bit of tape on the working-yarn tip to make a stiff needle"],[],[],["Knot ends in pairs so the weave can't unravel"]]},
  {"id":"cw-god-eye-charm","title":"Diamond Charm Weaving","altNames":["Stick-Cross Yarn Diamond","Woven Wall Charm","Crossed-Stick Diamond"],"type":"Craft","place":"Both","ageMin":8,"ageMax":15,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Cross two craft sticks and wind yarn round and round to grow a bright woven diamond charm with crisp color bands.","materials":["Craft sticks, two per child","Yarn, assorted colors","Scissors, child-safe"],"materialTags":["Craft sticks","Yarn","Scissors"],"steps":["Cross two craft sticks into a plus sign and lash the center tight by winding yarn diagonally over and over the joint.","Holding the cross steady, bring the yarn to one arm and wrap it once fully around that stick.","Carry the yarn to the next arm clockwise and wrap once around it, then continue arm to arm so the yarn lies flat between sticks.","Keep circling the same direction, each lap sitting just outside the last, to build outward diamond bands.","Change colors by knotting on a new yarn close to a stick and hiding the tail under the next wraps.","Stop near the stick ends, tie off, and add a hanging loop on one arm; tassels on the other three are optional."],"notes":"The trick that confuses kids is wrapping each stick only once before moving on; over-wrapping bunches the yarn. Distinct from the existing Ojo de Dios entry by using stripe-band color planning and a charm-sized finish.","safety":"Craft stick tips can have splinters, so run a thumb over the ends and set aside any rough sticks before starting.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"God's Eye yarn weaving for kids","url":"https://www.youtube.com/watch?v=brokkOAl0bQ"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/summer-crafts-for-kids/"}],"variations":["Use three sticks for a six-point star charm instead of four points.","Leave a gap of bare stick between two color bands for a floating-ring effect."],"subsets":[["Wrap the center lashing extra tight so the cross can't wobble"],[],["Say 'wrap, move, wrap, move' out loud to keep the rhythm"],[],[],[]]},
  {"id":"cw-finger-knit-chain","title":"Finger-Knit Cords","altNames":["No-Needle Finger Knitting","Hand-Loom Yarn Rope","Finger-Crochet Chain"],"type":"Craft","place":"Both","ageMin":7,"ageMax":14,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"None","blurb":"Use only your fingers to loop yarn into a long stretchy knitted cord for a bracelet, headband, or jump-rope-length rope.","materials":["Yarn, thick if available, one ball per few children","Scissors, child-safe"],"materialTags":["Yarn","Scissors"],"steps":["Make a slip knot and slide it onto your index finger, leaving a short tail to hold.","Wrap the working yarn over the back of all four fingers, then wrap a second time so each finger holds two loops.","Starting at one finger, lift the bottom loop up and over the top loop and off the fingertip, repeating across all four fingers.","Wrap a fresh pass across the fingers and again lift each bottom loop over the top, watching the knit cord grow down the back of your hand.","Keep wrapping and lifting; gently tug the cord downward now and then to even out the stitches.","When it is long enough, cut the yarn, thread the tail through the four remaining loops, and pull tight to close the end."],"notes":"This is a calm anchor activity that needs zero prep and travels anywhere. The 'bottom loop over the top' move is the only thing to model slowly; once it clicks, kids zone in happily.","safety":"Tell kids not to wrap the yarn so tightly around their fingers that the tips turn red, and to loosen if their fingers tingle.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Finger knitting for absolute beginners","url":"https://www.youtube.com/watch?v=_rjrRZmrsRg"}],"links":[{"label":"How-to & more ideas","url":"https://www.redtedart.com/category/paper-crafts/"}],"variations":["Knit a long cord and coil it into a flat spiral, stitching the coils to make a coaster.","Hold two yarn colors together to knit a candy-stripe cord."],"subsets":[["Leave the loops loose enough to slide off easily"],[],["Go slow on the first row; speed comes after"],[],[],["Pull the closing tail snug so it can't unravel"]]},
  {"id":"cw-braided-friendship-cord","title":"Braided Yarn Keychains","altNames":["Three-Strand Braid Cords","Plaited Zipper Pulls","Braided Wrist Cords"],"type":"Craft","place":"Both","ageMin":6,"ageMax":12,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Tape down three yarn strands and braid a sturdy color-pop cord that becomes a keychain, zipper pull, or backpack tag.","materials":["Yarn, assorted colors","Scissors, child-safe","Masking tape, one roll","Pony beads, assorted (optional)"],"materialTags":["Yarn","Scissors","Masking tape","Pony beads"],"steps":["Cut three strands of yarn a little longer than a forearm, choosing two or three colors.","Line the strands up, knot them together near one end, and tape the knot to the table to hold it steady.","Braid by crossing the right strand over the middle, then the left strand over the middle, and repeat down the length.","Keep the strands flat and pull each cross snug so the braid stays even and tight.","Knot the bottom end to lock the braid, then thread a few beads on the loose tails if you like.","Loop the braid and tie it into a ring for a keychain or zipper pull."],"notes":"Great low-floor starter that builds the hand pattern for friendship bracelets later. Pair kids who get braiding with kids who don't so the helper can hold strands taut.","safety":"Keep finished loops too small to fit over a head, and remind kids never to put cord loops around necks.","ages":["g13","g46"],"rating":0,"media":[{"title":"DIY yarn braid keychain","url":"https://www.youtube.com/watch?v=g1Jb3peDF4c"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/summer-crafts-for-kids/"}],"variations":["Braid four or more strands held in two groups for a fatter cord.","Use one shiny and two matte colors for a contrast braid."],"subsets":[["Knot one end and tape it down for an extra anchor"],[],["Chant 'right over, left over' to keep the rhythm"],[],[],[]]},
  {"id":"cw-yarn-wrapped-letters","title":"Yarn-Wrapped Initials","altNames":["Wrapped Cardboard Letters","Yarn Monogram Craft","Wound-Letter Name Art"],"type":"Craft","place":"Both","ageMin":7,"ageMax":14,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Wind colorful yarn tightly around a chunky cardboard letter to make a soft, fuzzy initial you can pin up in your bunk or room.","materials":["Cardboard, cut into chunky block letters","Yarn, assorted colors","Scissors, child-safe","Glue, washable","Masking tape, one roll"],"materialTags":["Cardboard","Yarn","Scissors","Glue","Masking tape"],"steps":["Choose a pre-cut chunky cardboard letter, usually the first letter of your name.","Dab a little glue on the back and press the yarn tail down, or tape it, to anchor your starting point.","Wrap yarn snugly around the letter, laying wraps side by side so no cardboard peeks through.","At tricky corners and curves, wind a few extra wraps and angle them to keep full coverage.","To switch colors, tuck the old tail under recent wraps and start the new color over it.","Wrap to the end, tuck and glue the final tail on the back, and add a yarn loop for hanging."],"notes":"Cut the letters chunky and avoid thin spots like the crossbar of an A, which are hard to wrap. Block letters without holes (like L, C, J) are easiest for younger kids.","safety":"Use glue sparingly and keep fingers clear of glue spots while wrapping so yarn does not stick hands together.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Yarn-wrapped cardboard letters","url":"https://www.youtube.com/watch?v=psuWM1sz4bo"}],"links":[{"label":"How-to & more ideas","url":"https://www.redtedart.com/category/paper-crafts/"}],"variations":["Wrap a heart or star shape instead of a letter.","Wrap in ombre by shifting through shades of one color."],"subsets":[["Counselors pre-cut letters; offer simple shapes for ages 7-8"],["Anchor the tail well or the whole wrap loosens"],[],["Cross the wrap over itself at sharp inside corners"],[],[]]},
  {"id":"cw-pom-pom-fork","title":"Fork-Wound Pom-Poms","altNames":["Fork Pom-Pom Making","Mini Yarn Puffs","Wound-Yarn Pom-Poms"],"type":"Craft","place":"Both","ageMin":7,"ageMax":13,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Wind yarn around a plastic fork, tie it off tight, and snip it into a fluffy pom-pom to string into garlands or clip onto a bag.","materials":["Sturdy plastic forks, one per child","Yarn, assorted colors","Scissors, child-safe"],"materialTags":["Yarn","Scissors","No materials"],"steps":["Wrap yarn around the four tines of a fork many times, the more wraps the fluffier the pom, until it feels fat.","Cut a separate short piece of yarn and thread it through the gap between the middle tines.","Pull that tie around the whole bundle and knot it as tightly as you possibly can in the center.","Slide the bundle off the fork end carefully, keeping the center knot tight.","Snip through all the looped edges around the outside so the bundle blooms open.","Roll it in your palms and trim any long straggly strands to round it into a neat ball."],"notes":"The make-or-break step is the center tie: if it is not brutally tight, the pom falls apart when cut. Have kids loop the tie twice and pull with a partner if needed.","safety":"Use only smooth plastic forks with no cracked or sharp tines, and cut the loops slowly so scissors stay clear of fingers holding the bundle.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"How to make pom-poms with a fork","url":"https://www.youtube.com/watch?v=ALuexo_mUKc"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/summer-crafts-for-kids/"}],"variations":["Use two colors at once for a speckled pom.","Tie several poms onto a yarn string to make a garland."],"subsets":[["More wraps equals a fuller pom; aim for 50-plus"],[],["Knot the center tie twice, hard"],[],["Cut all the way around so it opens evenly"],[]]},
  {"id":"cw-straw-bead-weave","title":"Drinking-Straw Loom Bands","altNames":["Straw Loom Weaving","Tube-Loom Bracelets","Straw Heddle Weave"],"type":"Craft","place":"Both","ageMin":9,"ageMax":15,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Turn a handful of plastic straws into a clever finger loom and weave a flat striped band that slides off as a bracelet or strap.","materials":["Plastic drinking straws, three to five per child","Yarn, assorted colors","Scissors, child-safe","Masking tape, one roll"],"materialTags":["Straws","Yarn","Scissors","Masking tape"],"steps":["Cut three to five straws to the same shorter length and lay them side by side.","Thread one long warp yarn down through each straw and tie all the warp ends together in a knot above the straws.","Tape the knot to your shirt or the table so the straws hang down with warp yarn inside each one.","Weave a weft yarn over and under the straws, sliding finished rows up off the straw tops onto the warp threads above.","Keep weaving and pushing rows up; as the band grows it collects on the warp threads above the straws.","When long enough, slide the whole band off the straw tops, untie the warp knot, and knot the ends to finish a bracelet."],"notes":"This portable loom fascinates older kids and produces a real wearable band. Pre-cutting straws to length and pre-threading warp for younger groups saves a lot of fiddling.","safety":"Cut straws on a flat surface with the blade moving away from the body, since short straws can roll and slip under the scissors.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Weaving with drinking straws and yarn","url":"https://www.youtube.com/watch?v=LFtDxFN_HpI"}],"links":[{"label":"How-to & more ideas","url":"https://www.redtedart.com/category/paper-crafts/"}],"variations":["Add a pony bead onto the warp now and then for texture.","Use more straws for a wider strap or belt."],"subsets":[["Counselors can pre-thread the warp for ages 9-10"],["A safety pin or paperclip helps pull yarn through a straw"],[],["Slide rows up often so the straws stay free to weave"],[],["Knot ends firmly so the band holds its shape"]]},
  {"id":"cw-cardboard-lacing-card","title":"Yarn Lacing Cards","altNames":["Cardboard Sewing Cards","Punch-Hole Lacing Art","Yarn Stitch Cards"],"type":"Craft","place":"Both","ageMin":6,"ageMax":11,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Lace yarn in and out of pre-punched holes around a cardboard shape to stitch a picture or border, like sewing without a needle.","materials":["Cardboard shapes with punched holes","Yarn, assorted colors","Scissors, child-safe","Masking tape, one roll"],"materialTags":["Cardboard","Yarn","Scissors","Masking tape"],"steps":["Pick a cardboard shape that already has holes punched around its edge or across a simple design.","Wrap a bit of tape tightly around one yarn end to make a stiff tip that pokes through holes easily.","Tape the other yarn end to the back of the card so your stitching has an anchor.","Lace the stiff tip up through one hole and down through the next, following the holes around or across.","Try a running line, a crisscross border, or zigzags by choosing which holes to skip.","When done or out of yarn, tape the tail to the back and start a new color if you want."],"notes":"A gentle, focused craft perfect for the youngest campers and for calming a hyped group. Punch holes ahead of time and keep designs simple so frustration stays low.","safety":"The taped yarn tip is firm but blunt; remind kids to push it gently through holes, not jab it toward a partner.","ages":["g13","g46"],"rating":0,"media":[{"title":"Cardboard yarn lacing craft","url":"https://www.youtube.com/watch?v=gMNoF1KPqvA"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/summer-crafts-for-kids/"}],"variations":["Lace a whip-stitch all the way around the edge for a finished border.","Spell out a short word with a single straight line of stitches."],"subsets":[["Counselors pre-punch holes; space them a thumb-width apart"],["Re-tape the tip if it frays soft"],[],["Show one stitch slowly, then let them repeat the pattern"],[],[]]},
  {"id":"cw-tablet-warp-band","title":"Spoke-Wheel Cord Braiding","altNames":["Disc Braiding Wheel","Kumihimo-Style Cord","Foam Disc Friendship Cord"],"type":"Craft","place":"Both","ageMin":9,"ageMax":15,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Slot yarn into a notched cardboard wheel and move strands by a simple counting rhythm to braid a round, spiraling friendship cord.","materials":["Cardboard circles with edge notches and a center hole","Yarn, assorted colors","Scissors, child-safe"],"materialTags":["Cardboard","Yarn","Scissors"],"steps":["Take a round cardboard disc that has an odd number of edge notches and a small hole in the center.","Cut several yarn strands, knot them together, and drop the knot through the center hole so the strands fan out the top.","Tuck one strand into each notch, leaving exactly one notch empty to drive the pattern.","Counting from the empty notch, jump down to the third filled strand and move it up into the empty notch.","Turn the disc and repeat the same 'count to three and move' step over and over, watching a round cord form under the disc.","When the cord is long enough, lift all strands out, knot the end, and slide the disc off to finish."],"notes":"The repetitive count-and-move rhythm is meditative once it clicks and produces a surprisingly professional round cord. Make discs ahead; an odd notch count is essential for the spiral to work.","safety":"Discs can have rough cut edges, so smooth the notches with a thumb and hand out only clean-cut discs.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Friendship bracelets with a cardboard disc","url":"https://www.youtube.com/watch?v=yYU9mSua8zc"}],"links":[{"label":"How-to & more ideas","url":"https://www.redtedart.com/category/paper-crafts/"}],"variations":["Use a pattern of dark and light strands to make a visible color spiral.","Slow down and call the moves as a group so beginners stay in sync."],"subsets":[["Counselors cut the discs; 7 notches works well to start"],[],["Always leave one notch empty; it sets the whole pattern"],["The same move repeats forever once you learn it"],[],[]]},
  {"id":"cw-rag-strip-weave","title":"Fabric-Strip Mat Weaving","altNames":["Rag Strip Loom","Woven Scrap Mat","Strip Weave Placemat"],"type":"Craft","place":"Both","ageMin":8,"ageMax":14,"durationMin":60,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Weave torn fabric strips through a yarn-warped cardboard loom to make a thick, cozy little mat with bold color blocks.","materials":["Large cardboard rectangles with edge notches","Yarn, assorted colors","Fabric scraps torn into long strips","Scissors, child-safe"],"materialTags":["Cardboard","Yarn","Scissors","No materials"],"steps":["Take a notched cardboard rectangle and run yarn back and forth through the notches to make a tight set of warp threads.","Choose torn fabric strips in a few colors and roll each one loosely so it feeds through easily.","Weave the first fabric strip over and under the warp threads all the way across, then turn and come back the opposite way.","Push each row down firmly so the thicker fabric packs into solid color blocks.","Start a new strip by overlapping the old tail by a few fingers and continuing the over-under pattern.","Fill the loom, then carefully slip the weave off the notches and knot or tuck the warp ends to finish the mat."],"notes":"The chunky fabric weaves fast and forgivingly, so this suits kids who find thin yarn fiddly. Pre-tear strips into long, even widths; ragged-width strips make a lumpy mat.","safety":"Tear fabric strips ahead of time so kids are not pulling hard on fabric that could snap back, and keep scissors flat on the table.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Fabric weaving at home","url":"https://www.youtube.com/watch?v=JCKqh1m9baU"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/summer-crafts-for-kids/"}],"variations":["Weave only yarn for a finer mat, or only fabric for a chunky one.","Plan stripes by grouping same-color strips together."],"subsets":[["Counselors tear strips two fingers wide and arm-length long"],[],["Leave a little slack at the turn so edges do not pull in"],["Pack rows tight for a sturdy mat"],[],["Knot warp ends in pairs so the mat holds"]]},
  {"id":"cw-woven-bookmark","title":"Woven Yarn Bookmarks","altNames":["Mini Loom Bookmarks","Strip Weave Bookmark","Notched-Card Bookmark"],"type":"Craft","place":"Both","ageMin":7,"ageMax":13,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Weave a slim, striped band on a tall skinny cardboard loom and finish it with a tassel for a bookmark that says you made it.","materials":["Tall narrow cardboard strips with top and bottom notches","Yarn, assorted colors","Scissors, child-safe","Masking tape, one roll"],"materialTags":["Cardboard","Yarn","Scissors","Masking tape"],"steps":["Notch the short top and bottom edges of a tall narrow cardboard strip with a small odd number of slits.","Lay the warp by running yarn straight down from top notches to matching bottom notches, taping ends on the back.","Weave a weft yarn over and under across the narrow warp, turning at each edge to come back the other way.","Pack rows tight and switch colors in stripes to design your bookmark as you go.","When the band is woven nearly full, slip it off the notches and gently cut the bottom warp loops free.","Knot the freed warp threads into a little tassel at the bottom and tuck or knot the top to finish."],"notes":"The narrow loom means a quick win, which keeps reluctant weavers engaged. Coach kids to keep the edges straight by not pulling the turn too tight, or the bookmark hourglasses.","safety":"Cut the bottom warp loops a few at a time with the points aimed away from the hand holding the weaving.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Cardboard loom bookmark","url":"https://www.youtube.com/watch?v=BMIkXRS1378"}],"links":[{"label":"How-to & more ideas","url":"https://www.redtedart.com/category/paper-crafts/"}],"variations":["Weave initials by switching a contrasting color in the middle rows.","Skip the tassel and instead loop a yarn pull through the top for a different finish."],"subsets":[["Use 5 warp threads for a slim bookmark"],[],["Wrap tape on the weft tip for an easy needle"],[],[],["Knot the tassel threads together so they hang neatly"]]},
];
